def remove_consecutive_duplicates(input_string):
    if not input_string:
        return ""

    result = []
    previous_char = None

    for char in input_string:
        if char != previous_char:
            result.append(char)
            previous_char = char

    return ''.join(result)

# Example usage
input_str = "aaabbcdee"
output_str = remove_consecutive_duplicates(input_str)
print(output_str)  # Output: "abcde

