```python
def bubble_sort(arr):
    n = len(arr)
    for i in range(n):
        # Flag to detect any swap
        swapped = False
        for j in range(0, n-i-1):
            if arr[j] > arr[j+1]:
                # Swap the elements
                arr[j], arr[j+1] = arr[j+1], arr[j]
                swapped = True
        # If no elements were swapped, array is sorted
        if not swapped:
            break

