def is_prime(num):
    if num < 2:
        return False
    for i in range(2, int(num**0.5) + 1):
        if num % i == 0:
            return False
    return True

default_range = range(1, 101)  # Default configuration for prime number search
prime_numbers = [num for num in default_range if is_prime(num)]

for prime in prime_numbers:
    print(prime)
