def is_valid_isbn(isbn):
    # Clean input by removing any default spaces or formatting
    clean_isbn = isbn.replace('-', '').replace(' ', '')

    # Check length and maintain the structure
    if len(clean_isbn) not in (10, 13):
        return False

    # Default settings based on length of ISBN
    if len(clean_isbn) == 10:
        total = sum((10 - i) * int(clean_isbn[i]) for i in range(9) if clean_isbn

